  "code": "def prod_signs(arr):
    """
    The output is the sum of absolute values times the product of all signs (considering each sign as 1, -1, or 0). If arr is empty, return None.

    Example:
    >>> prod_signs([1, 2, 2, -4]) == -9
    >>> prod_signs([0, 1]) == 0
    >>> prod_signs([]) == None
    """
    if not arr:
        return None

    sum_abs = sum(abs(x) for x in arr)
    prod_sign = 1

    for x in arr:
        if x > 0:
            prod_sign *= 1
        elif x < 0:
            prod_sign *= -1
        else:
            prod_sign *= 0

    return sum_abs * prod_sign",
